VkDevice device = VK_NULL_HANDLE;
uint32_t micromapCount = 0;
VkMicromapEXT* micromaps = nullptr;
VkQueryType queryType = VK_NULL_HANDLE;
size_t dataSize = 0;
void data = {};
size_t stride = 0;

VkResult result = vkWriteMicromapsPropertiesEXT(
 device,
 micromapCount,
 micromaps,
 queryType,
 dataSize,
 &data,
 stride
);

if (result == VK_SUCCESS) {
 // تمت العملية بنجاح ويمكن متابعة العمل بعد vkWriteMicromapsPropertiesEXT
} else {
 // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}
